const ethers = require('ethers');

class SecureDApp {
  constructor() {
    this.provider = null;
    this.signer = null;
    this.userAddress = null;
    this.transactionQueue = new Map();
    this.pendingTransactions = new Set();
    this.maxGasPrice = ethers.parseUnits('100', 'gwei');
    this.maxGasLimit = 500000n;
    this.trustedContracts = new Set();
    this.transactionTimeout = 300000; // 5 minutes
  }

  async initialize() {
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask or compatible wallet not found');
    }

    this.provider = new ethers.BrowserProvider(window.ethereum);
    
    window.ethereum.on('accountsChanged', (accounts) => {
      this.handleAccountsChanged(accounts);
    });

    window.ethereum.on('chainChanged', () => {
      window.location.reload();
    });
  }

  async connectWallet() {
    try {
      const accounts = await window.ethereum.request({ 
        method: 'eth_requestAccounts' 
      });
      
      this.signer = await this.provider.getSigner();
      this.userAddress = accounts[0];
      
      return {
        success: true,
        address: this.userAddress
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  handleAccountsChanged(accounts) {
    if (accounts.length === 0) {
      this.userAddress = null;
      this.signer = null;
    } else {
      this.userAddress = accounts[0];
      this.signer = this.provider.getSigner();
    }
  }

  addTrustedContract(address) {
    if (!ethers.isAddress(address)) {
      throw new Error('Invalid contract address');
    }
    this.trustedContracts.add(address.toLowerCase());
  }

  removeTrustedContract(address) {
    this.trustedContracts.delete(address.toLowerCase());
  }

  validateAddress(address) {
    if (!address || typeof address !== 'string') {
      return false;
    }
    return ethers.isAddress(address);
  }

  sanitizeInput(input) {
    if (typeof input === 'string') {
      return input.trim();
    }
    return input;
  }

  validateTransactionParams(params) {
    const errors = [];

    if (!this.validateAddress(params.contractAddress)) {
      errors.push('Invalid contract address');
    }

    if (!params.functionName || typeof params.functionName !== 'string') {
      errors.push('Invalid function name');
    }

    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(params.functionName)) {
      errors.push('Function name contains invalid characters');
    }

    if (params.value) {
      try {
        const value = ethers.parseEther(params.value.toString());
        if (value < 0n) {
          errors.push('Value cannot be negative');
        }
      } catch (e) {
        errors.push('Invalid value format');
      }
    }

    if (params.gasLimit) {
      const gasLimit = BigInt(params.gasLimit);
      if (gasLimit > this.maxGasLimit) {
        errors.push(`Gas limit exceeds maximum allowed: ${this.maxGasLimit}`);
      }
      if (gasLimit < 21000n) {
        errors.push('Gas limit too low');
      }
    }

    if (params.gasPrice) {
      const gasPrice = ethers.parseUnits(params.gasPrice.toString(), 'gwei');
      if (gasPrice > this.maxGasPrice) {
        errors.push(`Gas price exceeds maximum allowed: ${ethers.formatUnits(this.maxGasPrice, 'gwei')} gwei`);
      }
    }

    return {
      valid: errors.length === 0,
      errors
    };
  }

  async estimateGas(contract, functionName, args, value) {
    try {
      const gasEstimate = await contract[functionName].estimateGas(...args, {
        value: value || 0n
      });
      
      const gasWithBuffer = (gasEstimate * 120n) / 100n;
      
      return gasWithBuffer > this.maxGasLimit ? this.maxGasLimit : gasWithBuffer;
    } catch (error) {
      throw new Error(`Gas estimation failed: ${error.message}`);
    }
  }

  async getGasPrice() {
    try {
      const feeData = await this.provider.getFeeData();
      
      if (feeData.maxFeePerGas && feeData.maxPriorityFeePerGas) {
        return {
          maxFeePerGas: feeData.maxFeePerGas > this.maxGasPrice ? this.maxGasPrice : feeData.maxFeePerGas,
          maxPriorityFeePerGas: feeData.maxPriorityFeePerGas
        };
      }
      
      const gasPrice = feeData.gasPrice || ethers.parseUnits('20', 'gwei');
      return {
        gasPrice: gasPrice > this.maxGasPrice ? this.maxGasPrice : gasPrice
      };
    } catch (error) {
      return {
        gasPrice: ethers.parseUnits('20', 'gwei')
      };
    }
  }

  async buildTransaction(params) {
    const validation = this.validateTransactionParams(params);
    if (!validation.valid) {
      throw new Error(`Validation failed: ${validation.errors.join(', ')}`);
    }

    if (!this.signer) {
      throw new Error('Wallet not connected');
    }

    const contractAddress = this.sanitizeInput(params.contractAddress);
    const functionName = this.sanitizeInput(params.functionName);
    const args = params.args || [];
    const abi = params.abi;

    if (!Array.isArray(abi)) {
      throw new Error('Invalid ABI format');
    }

    const contract = new ethers.Contract(contractAddress, abi, this.signer);

    if (typeof contract[functionName] !== 'function') {
      throw new Error(`Function ${functionName} not found in contract`);
    }

    const value = params.value ? ethers.parseEther(params.value.toString()) : 0n;

    const gasEstimate = await this.estimateGas(contract, functionName, args, value);
    const gasPriceData = await this.getGasPrice();

    const txOptions = {
      value,
      gasLimit: params.gasLimit ? BigInt(params.gasLimit) : gasEstimate,
      ...gasPriceData
    };

    return {
      contract,
      functionName,
      args,
      txOptions,
      contractAddress
    };
  }

  async simulateTransaction(params) {
    try {
      const { contract, functionName, args, txOptions } = await this.buildTransaction(params);

      const result = await contract[functionName].staticCall(...args, txOptions);

      return {
        success: true,
        result,
        estimatedGas: txOptions.gasLimit.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message,
        reason: error.reason || 'Transaction simulation failed'
      };
    }
  }

  generateTransactionId() {
    return `tx_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  async requestUserConfirmation(transactionDetails) {
    return new Promise((resolve) => {
      const confirmationData = {
        id: this.generateTransactionId(),
        timestamp: Date.now(),
        details: transactionDetails,
        status: 'pending_confirmation'
      };

      this.transactionQueue.set(confirmationData.id, confirmationData);

      const timeoutId = setTimeout(() => {
        this.transactionQueue.delete(confirmationData.id);
        resolve({
          confirmed: false,
          reason: 'Confirmation timeout'
        });
      }, this.transactionTimeout);

      const confirmButton = document.createElement('div');
      confirmButton.innerHTML = `
        <div id="tx-confirmation-${confirmationData.id}" style="position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); background: white; padding: 20px; border: 2px solid #333; z-index: 10000; max-width: 500px;">
          <h3>Confirm Transaction</h3>
          <p><strong>Contract:</strong> ${transactionDetails.contractAddress}</p>
          <p><strong>Function:</strong> ${transactionDetails.functionName}</p>
          <p><strong>Value:</strong> ${transactionDetails.value || '0'} ETH</p>
          <p><strong>Gas Limit:</strong> ${transactionDetails.gasLimit}</p>
          <p><strong>Estimated Cost:</strong> ${transactionDetails.estimatedCost} ETH</p>
          <button id="confirm-${confirmationData.id}">Confirm</button>
          <button id="reject-${confirmationData.id}">Reject</button>
        </div>
      `;

      document.body.appendChild(confirmButton);

      document.getElementById(`confirm-${confirmationData.id}`).onclick = () => {
        clearTimeout(timeoutId);
        document.getElementById(`tx-confirmation-${confirmationData.id}`).remove();
        this.transactionQueue.delete(confirmationData.id);
        resolve({ confirmed: true });
      };

      document.getElementById(`reject-${confirmationData.id}`).onclick = () => {
        clearTimeout(timeoutId);
        document.getElementById(`tx-confirmation-${confirmationData.id}`).remove();
        this.transactionQueue.delete(confirmationData.id);
        resolve({ confirmed: false, reason: 'User rejected' });
      };
    });
  }

  async sendTransaction(params) {
    try {
      const { contract, functionName, args, txOptions, contractAddress } = await this.buildTransaction(params);

      const simulation = await this.simulateTransaction(params);
      if (!simulation.success) {
        throw new Error(`Transaction would fail: ${simulation.error}`);
      }

      const feeData = await this.provider.getFeeData();
      const estimatedCost = ethers.formatEther(
        (txOptions.gasLimit * (feeData.gasPrice || txOptions.gasPrice || 0n)) + (txOptions.value || 0n)
      );

      const confirmation = await this.requestUserConfirmation({
        contractAddress,
        functionName,
        args: JSON.stringify(args),
        value: ethers.formatEther(txOptions.value || 0n),
        gasLimit: txOptions.gasLimit.toString(),
        estimatedCost
      });

      if (!confirmation.confirmed) {
        throw new Error(confirmation.reason || 'Transaction rejected by user');
      }

      const tx = await contract[functionName](...args, txOptions);
      
      this.pendingTransactions.add(tx.hash);

      const receipt = await tx.wait();

      this.pendingTransactions.delete(tx.hash);

      return {
        success: true,
        transactionHash: tx.hash,
        receipt: {
          blockNumber: receipt.blockNumber,
          gasUsed: receipt.gasUsed.toString(),
          status: receipt.status,
          logs: receipt.logs
        }
      };
    } catch (error) {
      return {
        success: false,
        error: error.message,
        code: error.code
      };
    }
  }

  async readContract(params) {
    const validation = this.validateTransactionParams({
      ...params,
      value: '0'
    });
    
    if (!validation.valid) {
      throw new Error(`Validation failed: ${validation.errors.join(', ')}`);
    }

    const contractAddress = this.sanitizeInput(params.contractAddress);
    const functionName = this.sanitizeInput(params.functionName);
    const args = params.args || [];
    const abi = params.abi;

    const contract = new ethers.Contract(contractAddress, abi, this.provider);

    try {
      const result = await contract[functionName](...args);
      return {
        success: true,
        result
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async getTransactionStatus(txHash) {
    try {
      const receipt = await this.provider.getTransactionReceipt(txHash);
      
      if (!receipt) {
        return {
          status: 'pending',
          confirmed: false
        };
      }

      return {
        status: receipt.status === 1 ? 'success' : 'failed',
        confirmed: true,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString()
      };
    } catch (error) {
      return {
        status: 'error',
        error: error.message
      };
    }
  }

  async getBalance(address) {
    try {
      const balance = await this.provider.getBalance(address || this.userAddress);
      return {
        success: true,
        balance: ethers.formatEther(balance),
        wei: balance.toString()
      };
    } catch (error) {
      return {
        success: false,
        error: error.message
      };
    }
  }

  async getNetwork() {
    try {
      const network = await this.provider.getNetwork();
      return {
        chainId: network.chainId.toString(),
        name: network.name
      };
    } catch (error) {
      throw new Error(`Failed to get network: ${error.message}`);
    }
  }

  getPendingTransactions() {
    return Array.from(this.pendingTransactions);
  }

  clearPendingTransactions() {
    this.pendingTransactions.clear();
  }

  disconnect() {
    this.signer = null;
    this.userAddress = null;
    this.clearPendingTransactions();
    this.transactionQueue.clear();
  }
}

const dapp = new SecureDApp();

